0.15) 100%);pointer-events:none;z-index:0}\n.prot-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.prot-header{text-align:center;margin-bottom:60px}\n.prot-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.2em;color:#0369a1;display:block;margin-bottom:16px}\n.prot-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(32px,3.5vw,44px);font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.prot-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.prot-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.prot-card{background:linear-gradient(180deg,#f8fafc 0%,#fff 100%);border:1px solid #e2e8f0;border-radius:20px;padding:32px;transition:all 0.3s ease}\n.prot-card:hover{box-shadow:0 12px 40px rgba(0,0,0,0.08);border-color:#00AFF0}\n.prot-icon{width:56px;height:56px;background:linear-gradient(135deg,#00AFF0,#003CC8);border-radius:16px;display:flex;align-items:center;justify-content:center;margin-bottom:20px}\n.prot-icon svg{width:28px;height:28px;stroke:#fff}\n.prot-card h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 20px;padding:0}\n.prot-points{margin-bottom:20px}\n.prot-point{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;line-height:1.6;padding:12px 0;border-bottom:1px solid #f1f5f9}\n.prot-point:last-child{border-bottom:none}\n.prot-point strong{color:#000864;display:block;margin-bottom:4px}\n.prot-proof{font-family:\'Noto Sans\',sans-serif;font-size:13px;font-style:italic;color:#15803d;background:#f0fdf4;padding:12px 16px;border-radius:12px;text-align:center}\n@media(max-width:1024px){\n  .prot-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .prot-section{padding:80px 20px}\n}\n@media(prefers-reduced-motion:reduce){.prot-card{transition:none !important}}\n.et_pb_section .prot-label {\n            line-height: 19.2px !important;\n        \n            margin-bottom: 12px;\n}\n\n.et_pb_section .prot-proof {\n            line-height: 20.8px !important;\n        }\n/* === CTA: คุยตัวเลขสำหรับบริษัทของคุณ === */\n.ec-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ec-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.ec-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.ec-cta-super-d{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.18;pointer-events:none;z-index:0;animation:superDGlow 3s ease-in-out infinite}\n@keyframes superDGlow{0%,100%{filter:drop-shadow(0 0 20px rgba(0,175,240,0.1))}50%{filter:drop-shadow(0 0 40px rgba(0,175,240,0.25))}}\n\n.ec-cta-container{position:relative;z-index:3;max-width:800px;margin:0 auto;text-align:center}\n.ec-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.ec-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.9);margin:0 0 40px;max-width:600px;margin-left:auto;margin-right:auto}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .ec-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .ec-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .ec-cta-container p{padding-bottom:0 !important}\n\n.ec-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.ec-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.ec-cta-btn:hover::before{left:100%}\n.ec-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.ec-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.ec-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.ec-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.ec-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.ec-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .ec-cta-title{font-size:28px;margin-bottom:16px}\n  .ec-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .ec-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .ec-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.ec-cta-btn{transition:none !important}.ec-cta-btn::before{display:none}}\n.et_pb_section .ec-cta-btn--ghost{color:#fff !important}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: เศรษฐศาสตร์พาร์ทเนอร์"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: เศรษฐศาสตร์พาร์ทเนอร์: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: เศรษฐศาสตร์พาร์ทเนอร์: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="econ-hero-section">\n      <div class="econ-hero-d-bg" aria-hidden="true"></div>\n      <div class="econ-hero-dot-overlay" aria-hidden="true"></div>\n      <div class="econ-hero-grain" aria-hidden="true"></div>\n      <div class="econ-hero-inner">\n        <div class="econ-hero-breadcrumb">\n          <a href="/partner-program/">โปรแกรมพันธมิตร</a>\n          <span>/</span>\n          <span>เศรษฐศาสตร์พาร์ทเนอร์</span>\n        </div>\n        <h1 class="econ-hero-title">ดูเศรษฐศาสตร์จริง —<span class="econ-hero-hl">ไม่ใช่ Sales Pitch</span></h1>\n        <p class="econ-hero-subtitle">ตัวเลขจริงเป็นเงินบาท สถานการณ์แบบอนุรักษ์นิยม ไม่มีการโฆษณาเกินจริง นี่คือรายละเอียดว่าโมเดลพาร์ทเนอร์ทำงานอย่างไรทางการเงิน — จากปีที่ 1 ที่ต้องอยู่รอด ถึงปีที่ 3 ที่สร้างสินทรัพย์</p>\n        <div class="econ-hero-proof">\n          <div class="econ-hero-proof-item">\n            <span class="econ-hero-proof-value">30-40%</span>\n            <span class="econ-hero-proof-label">มาร์จินลิขสิทธิ์</span>\n          </div>\n          <div class="econ-hero-proof-item">\n            <span class="econ-hero-proof-value">100%</span>\n            <span class="econ-hero-proof-label">รายได้บริการ</span>\n          </div>\n          <div class="econ-hero-proof-item">\n            <span class="econ-hero-proof-value">Fixed</span>\n            <span class="econ-hero-proof-label">ค่า MA คาดการณ์ได้</span>\n          </div>\n          <div class="econ-hero-proof-item">\n            <span class="econ-hero-proof-value">6 เดือน</span>\n            <span class="econ-hero-proof-label">คุ้มครอง Lead Lock</span>\n          </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Revenue: 4 Streams"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Revenue: 4 Streams: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Revenue: 4 Streams: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="rev-section">\n      <div class="rev-scene rev-scene-wrap" aria-hidden="true"></div>\n      <div class="rev-wave-top" aria-hidden="true"></div>\n      <div class="rev-inner">\n        <div class="rev-header">\n          <span class="rev-label">4 ช่องทางรายได้</span>\n          <h2 class="rev-title">รายได้พาร์ทเนอร์ทำงานอย่างไรจริงๆ</h2>\n          <p class="rev-subtitle">ต่างจากผู้ค้า SaaS ที่รายได้หยดเข้ามาเป็นปีๆ โมเดลของเราให้มาร์จินเริ่มต้นที่มากพอ บวกรายได้ต่อเนื่อง</p>\n        </div>\n        <div class="rev-grid">\n            <div class="rev-stream">\n              <div class="rev-stream-header">\n                <div class="rev-stream-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M9 12l2 2 4-4"/></svg></div>\n                <h3>รายได้ลิขสิทธิ์</h3>\n                <span class="rev-stream-tag">กระแสเงินสดเริ่มต้น</span>\n              </div>\n              <div class="rev-stream-body">\n                <p class="rev-stream-desc">คุณซื้อ License Key ในราคา Distributor ขายในราคาแนะนำ (SSP) ส่วนต่างคือ <strong>กำไรขั้นต้นทันที</strong> — มีกำไรตั้งแต่วันแรก</p>\n                <div class="rev-margin-grid"><div class="rev-margin-item">\n                    <span class="rev-margin-level">Silver Partner</span>\n                    <span class="rev-margin-value">มาร์จินที่แข็งแกร่ง</span>\n                  </div><div class="rev-margin-item">\n                    <span class="rev-margin-level">Gold Partner</span>\n                    <span class="rev-margin-value highlight">มาร์จินชั้นนำในอุตสาหกรรม</span>\n                  </div>\n                </div>\n                \n              </div>\n            </div>\n            <div class="rev-stream">\n              <div class="rev-stream-header">\n                <div class="rev-stream-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87m-4-12a4 4 0 010 7.75"/></svg></div>\n                <h3>รายได้บริการ</h3>\n                <span class="rev-stream-tag">เก็บ 100%</span>\n              </div>\n              <div class="rev-stream-body">\n                <p class="rev-stream-desc">DigiWin เป็นผู้ค้าผลิตภัณฑ์ ไม่ใช่คู่แข่งด้านบริการ <strong>คุณเก็บ 100%</strong> ของค่า Implementation, Customization และ Training ทั้งหมด</p>\n                <div class="rev-margin-grid"><div class="rev-margin-item">\n                    <span class="rev-margin-level">โปรเจกต์ Workflow iGP</span>\n                    <span class="rev-margin-value">แล้วแต่ขอบเขตงาน</span>\n                  </div><div class="rev-margin-item">\n                    <span class="rev-margin-level">โปรเจกต์ T100/MES</span>\n                    <span class="rev-margin-value highlight">เรียกเก็บรายชั่วโมง</span>\n                  </div>\n                </div>\n                <p class="rev-stream-note"><em>เรา "สละ" รายได้มาร์จินสูงนี้ให้พาร์ทเนอร์ เพื่อแลกกับการขยายตลาด</em></p>\n              </div>\n            </div>\n            <div class="rev-stream">\n              <div class="rev-stream-header">\n                <div class="rev-stream-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/><polyline points="17 6 23 6 23 12"/></svg></div>\n                <h3>การสนับสนุนต่อเนื่อง (MA)</h3>\n                <span class="rev-stream-tag">กระแสรายได้ประจำ</span>\n              </div>\n              <div class="rev-stream-body">\n                <p class="rev-stream-desc">คุณจ่ายให้ DigiWin <strong>ค่าธรรมเนียมประจำปีแบบคงที่</strong> (เริ่มปีที่ 2) สำหรับ Tier 2 Support — แก้ Bug หลัก, Patch และ R&D คุณให้บริการ Tier 1 Support และ <strong>กำหนดราคาเองกับลูกค้า</strong></p>\n                <div class="rev-margin-grid"><div class="rev-margin-item">\n                    <span class="rev-margin-level">ค่าใช้จ่ายของคุณกับ DigiWin</span>\n                    <span class="rev-margin-value">ค่าธรรมเนียมประจำปีคงที่</span>\n                  </div><div class="rev-margin-item">\n                    <span class="rev-margin-level">คุณเก็บจากลูกค้า</span>\n                    <span class="rev-margin-value highlight">คุณกำหนดราคาเอง</span>\n                  </div>\n                </div>\n                <p class="rev-stream-note"><em>ไม่มีการแบ่งกำไร ค่าใช้จ่ายของคุณคงที่และคาดการณ์ได้ คุณกำหนดราคากับลูกค้าเองและเก็บส่วนต่าง เมื่อฐานลูกค้าโต MA กลายเป็นแหล่งรายได้ที่คาดการณ์ได้มากที่สุด</em></p>\n              </div>\n            </div>\n            <div class="rev-stream">\n              <div class="rev-stream-header">\n                <div class="rev-stream-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><circle cx="12" cy="12" r="10"/><path d="M12 8v8m-4-4h8"/></svg></div>\n                <h3>Upsell & Cross-Sell</h3>\n                <span class="rev-stream-tag">ตัวคูณการเติบโต</span>\n              </div>\n              <div class="rev-stream-body">\n                <p class="rev-stream-desc">รายได้ไม่จบที่ Go-Live สร้าง IP บน <strong>แพลตฟอร์ม Digiwin.cloud PaaS</strong> Custom Module กลายเป็นสินทรัพย์ที่ขายลิขสิทธิ์ได้</p>\n                <div class="rev-margin-grid"><div class="rev-margin-item">\n                    <span class="rev-margin-level">Module เสริม</span>\n                    <span class="rev-margin-value">มาร์จินตามระดับเดียวกัน</span>\n                  </div><div class="rev-margin-item">\n                    <span class="rev-margin-level">ค่าแนะนำ (Referral)</span>\n                    <span class="rev-margin-value highlight">5-10% ของลิขสิทธิ์</span>\n                  </div>\n                </div>\n                <p class="rev-stream-note"><em>ลูกค้าคนเดียวสามารถสร้างยอดขายลิขสิทธิ์เพิ่มได้ 3-4 รายการใน 5 ปี</em></p>\n              </div>\n            </div>\n        </div>\n      </div>\n    </div><script>(function(){var c=document.querySelector(\'.rev-scene\');if(c){c.innerHTML=\'<svg viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice" aria-hidden="true"><path d="M100 750 Q300 740 500 700 Q700 640 900 500 Q1050 380 1150 250 Q1250 140 1350 50" stroke="#000864" stroke-width="2.5" fill="none" opacity="0.2"/><rect x="200" y="600" width="120" height="150" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/><rect x="200" y="500" width="120" height="100" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/><rect x="400" y="450" width="120" height="300" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/><rect x="400" y="320" width="120" height="130" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/><rect x="600" y="300" width="120" height="450" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/><rect x="600" y="180" width="120" height="120" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/><path d="M900 600 L900 350" stroke="#00AFF0" stroke-width="2" opacity="0.2"/><path d="M890 360 L900 340 L910 360" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.2"/><path d="M1000 550 L1000 250" stroke="#00AFF0" stroke-width="2" opacity="0.15"/><path d="M990 260 L1000 240 L1010 260" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.15"/><circle cx="1200" cy="500" r="40" stroke="#000864" stroke-width="1" fill="none" opacity="0.1" stroke-dasharray="4 3"/><circle cx="1200" cy="500" r="80" stroke="#000864" stroke-width="1" fill="none" opacity="0.07" stroke-dasharray="4 3"/><circle cx="1200" cy="500" r="120" stroke="#000864" stroke-width="1" fill="none" opacity="0.05" stroke-dasharray="4 3"/><circle cx="1200" cy="500" r="4" fill="#00AFF0" opacity="0.25"/><circle cx="350" cy="400" r="3" fill="#000864" opacity="0.12"/><circle cx="800" cy="250" r="4" fill="#000864" opacity="0.1"/></svg>\';}})()</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: 3-Year Projection"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: 3-Year Projection: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Journey: 3-Year Projection: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="jny-section">\n      <div class="jny-scene jny-scene-wrap" aria-hidden="true"></div>\n      <div class="jny-inner">\n        <div class="jny-header">\n          <span class="jny-label">สถานการณ์จำลอง ปีที่ 1-2-3</span>\n          <h2 class="jny-title">เส้นทาง 3 ปีของพาร์ทเนอร์</h2>\n          <p class="jny-subtitle">ประมาณการแบบอนุรักษ์นิยม ไม่มีการโฆษณาเกินจริง นี่คือสิ่งที่ความก้าวหน้าปกติของพาร์ทเนอร์ที่เริ่มจากผลิตภัณฑ์ SME ดูเป็น</p>\n        </div>\n        <div class="jny-grid">\n            <div class="jny-phase">\n              <div class="jny-phase-header year-1">\n                <div class="jny-badge">ปีที่ 1</div>\n                <h3>ลงทุนและเร่งตัว</h3>\n                <span class="jny-status">Silver Partner (Co-Delivery)</span>\n              </div>\n              <div class="jny-phase-body">\n                <p class="jny-reality"><strong>ความเป็นจริง:</strong> อย่าคาดหวังกำไรใน Q1-Q2 เน้นอบรมทีมหลักและปิดดีล "Pilot" แรกๆ โดยมี DigiWin ช่วยเต็มที่</p>\n                <div class="jny-activity">\n                  <span class="jny-activity-label">เป้าหมาย:</span>\n                  <span class="jny-activity-value">รับรอง 2 ที่ปรึกษา, ปิดดีล Workflow iGP Pilot 2 ราย</span>\n                </div>\n                <div class="jny-math"><div class="jny-math-row">\n                      <span>รายได้ลิขสิทธิ์</span>\n                      <span class="jny-math-value">มาร์จินที่แข็งแกร่ง</span>\n                    </div><div class="jny-math-row">\n                      <span>รายได้บริการ</span>\n                      <span class="jny-math-value">100% เป็นของคุณ</span>\n                    </div><div class="jny-math-row">\n                      <span>ต่อเนื่อง (MA)</span>\n                      <span class="jny-math-value">฿0 (ช่วงรับประกัน)</span>\n                    </div>\n                  <div class="jny-math-total">\n                    <span>เป้าหมายปีที่ 1</span>\n                    <span class="jny-math-total-value">สร้างรากฐาน</span>\n                  </div>\n                </div>\n                <p class="jny-outcome"><strong>ผลลัพธ์:</strong> เท่าทุนหรือขาดทุนเล็กน้อย แต่มี 2 Reference Site และทีมที่ได้รับการรับรอง คุณผ่าน "Valley of Death" แล้ว</p>\n              </div>\n            </div>\n            <div class="jny-phase">\n              <div class="jny-phase-header year-2">\n                <div class="jny-badge">ปีที่ 2</div>\n                <h3>เฟสกระแสเงินสด</h3>\n                <span class="jny-status">ก้าวสู่ Gold Partner</span>\n              </div>\n              <div class="jny-phase-body">\n                <p class="jny-reality"><strong>ความเป็นจริง:</strong> ทีมสามารถ Deploy iGP ได้โดยไม่ต้องมีพี่เลี้ยง หยุดเสียเวลาเรียนรู้ เริ่มใช้กลยุทธ์ "Reverse Cut" ด้วย MES</p>\n                <div class="jny-activity">\n                  <span class="jny-activity-label">ยอดขายใหม่:</span>\n                  <span class="jny-activity-value">3 โปรเจกต์ iGP + 1 MES แบบ Standalone</span>\n                </div>\n                <div class="jny-math"><div class="jny-math-row">\n                      <span>รายได้ลิขสิทธิ์</span>\n                      <span class="jny-math-value">เติบโตตามปริมาณ</span>\n                    </div><div class="jny-math-row">\n                      <span>รายได้บริการ</span>\n                      <span class="jny-math-value">100% เป็นของคุณ</span>\n                    </div><div class="jny-math-row">\n                      <span>ต่อเนื่อง (MA)</span>\n                      <span class="jny-math-value">เริ่มมีรายได้ประจำ</span>\n                    </div>\n                  <div class="jny-math-total">\n                    <span>เป้าหมายปีที่ 2</span>\n                    <span class="jny-math-total-value">ธุรกิจที่มีกำไร</span>\n                  </div>\n                </div>\n                <p class="jny-outcome"><strong>ผลลัพธ์:</strong> <strong>ธุรกิจที่มีกำไร</strong> รายได้บริการครอบคลุมค่าดำเนินการ รายได้ลิขสิทธิ์เป็นกำไรล้วน MA ครอบคลุมค่าเช่าออฟฟิศ</p>\n              </div>\n            </div>\n            <div class="jny-phase featured">\n              <div class="jny-phase-header year-3">\n                <div class="jny-badge">ปีที่ 3</div>\n                <h3>เฟสสร้างสินทรัพย์</h3>\n                <span class="jny-status">Gold Partner (เฉพาะทาง)</span>\n              </div>\n              <div class="jny-phase-body">\n                <p class="jny-reality"><strong>ความเป็นจริง:</strong> ไม่ต้อง "ล่า" อีกต่อไป เครื่องยนต์ "Farming" เริ่มทำงาน MA ครอบคลุมเงินเดือนที่ปรึกษารุ่นน้อง เริ่มพยายาม Upsell T100 หรือ AIoT ครั้งแรก</p>\n                <div class="jny-activity">\n                  <span class="jny-activity-label">ยอดขายใหม่:</span>\n                  <span class="jny-activity-value">4 iGP + 1 T100 Enterprise หรือ 2 MES เสริม</span>\n                </div>\n                <div class="jny-math"><div class="jny-math-row">\n                      <span>รายได้ลิขสิทธิ์</span>\n                      <span class="jny-math-value">ดีล Enterprise</span>\n                    </div><div class="jny-math-row">\n                      <span>รายได้บริการ</span>\n                      <span class="jny-math-value">100% เป็นของคุณ</span>\n                    </div><div class="jny-math-row">\n                      <span>ต่อเนื่อง (MA)</span>\n                      <span class="jny-math-value highlight">เติบโตแบบทบต้น</span>\n                    </div>\n                  <div class="jny-math-total">\n                    <span>เป้าหมายปีที่ 3</span>\n                    <span class="jny-math-total-value">สินทรัพย์ ไม่ใช่แค่งาน</span>\n                  </div>\n                </div>\n                <p class="jny-outcome"><strong>ผลลัพธ์:</strong> มูลค่าธุรกิจเปลี่ยน <strong>คุณมีกระแสรายได้ต่อเนื่องและฐานลูกค้าที่ยั่งยืน</strong> คุณสร้างสินทรัพย์ ไม่ใช่แค่งาน</p>\n              </div>\n            </div>\n        </div>\n        <div class="jny-summary">\n          <h4 class="jny-summary-title">แนวโน้มรายได้ 3 ปี</h4>\n          <div class="jny-bars">\n            <div class="jny-bar jny-bar--y1">\n              <span class="jny-bar-value">เร่งตัว</span>\n              <span class="jny-bar-label">ปีที่ 1: อยู่รอด</span>\n            </div>\n            <div class="jny-bar jny-bar--y2">\n              <span class="jny-bar-value">2-3 เท่า</span>\n              <span class="jny-bar-label">ปีที่ 2: มีกำไร</span>\n            </div>\n            <div class="jny-bar jny-bar--y3 featured">\n              <span class="jny-bar-value">4 เท่า+</span>\n              <span class="jny-bar-label">ปีที่ 3: สินทรัพย์</span>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div><script>(function(){var c=document.querySelector(\'.jny-scene\');if(c){c.innerHTML=\'<svg viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice" aria-hidden="true"><path d="M100 750 Q300 740 500 700 Q700 640 900 500 Q1050 380 1150 250 Q1250 140 1350 50" stroke="#000864" stroke-width="2.5" fill="none" opacity="0.2"/><rect x="200" y="600" width="120" height="150" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/><rect x="200" y="500" width="120" height="100" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/><rect x="400" y="450" width="120" height="300" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/><rect x="400" y="320" width="120" height="130" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/><rect x="600" y="300" width="120" height="450" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/><rect x="600" y="180" width="120" height="120" rx="4" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.1"/><path d="M900 600 L900 350" stroke="#00AFF0" stroke-width="2" opacity="0.2"/><path d="M890 360 L900 340 L910 360" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.2"/><path d="M1000 550 L1000 250" stroke="#00AFF0" stroke-width="2" opacity="0.15"/><path d="M990 260 L1000 240 L1010 260" stroke="#00AFF0" stroke-width="2" fill="none" opacity="0.15"/><circle cx="1200" cy="500" r="40" stroke="#000864" stroke-width="1" fill="none" opacity="0.1" stroke-dasharray="4 3"/><circle cx="1200" cy="500" r="80" stroke="#000864" stroke-width="1" fill="none" opacity="0.07" stroke-dasharray="4 3"/><circle cx="1200" cy="500" r="120" stroke="#000864" stroke-width="1" fill="none" opacity="0.05" stroke-dasharray="4 3"/><circle cx="1200" cy="500" r="4" fill="#00AFF0" opacity="0.25"/><circle cx="350" cy="400" r="3" fill="#000864" opacity="0.12"/><circle cx="800" cy="250" r="4" fill="#000864" opacity="0.1"/></svg>\';}})()</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protection: Risk Mitigation"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protection: Risk Mitigation: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Protection: Risk Mitigation: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="prot-section" data-particles>\n      <div class="prot-wave-right" aria-hidden="true"></div>\n      <div class="prot-inner">\n        <div class="prot-header">\n          <span class="prot-label">การบริหารความเสี่ยง</span>\n          <h2 class="prot-title">โครงสร้างการคุ้มครองของคุณ</h2>\n          <p class="prot-subtitle">พาร์ทเนอร์ชิปไม่ใช่แค่เรื่องรายได้ — แต่เกี่ยวกับการปกป้องการลงทุนและลดความเสี่ยงของคุณ</p>\n        </div>\n        <div class="prot-grid">\n            <div class="prot-card">\n              <div class="prot-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg></div>\n              <h3>คุ้มครองพื้นที่และป้องกัน Conflict</h3>\n              <div class="prot-points"><div class="prot-point"><strong>Lead Lock 6 เดือนอย่างหนัก:</strong> เมื่อคุณลงทะเบียน Lead ที่ผ่านเกณฑ์ จะถูกล็อคให้คุณตามกฎหมาย 6 เดือน (ต่ออายุ +3 ได้) ไม่มีใครเข้าถึงลูกค้าได้</div><div class="prot-point"><strong>การแบ่งส่วนเชิงโครงสร้าง:</strong> ทีมขายตรง DigiWin ดูแลเฉพาะบัญชีจีน/ไต้หวันที่ติดต่อเข้ามา ตลาดท้องถิ่นไทยเป็นของพาร์ทเนอร์โดยเฉพาะ</div><div class="prot-point"><strong>ข้อกำหนดไม่แข่งขัน:</strong> Master Agreement ระบุชัดเจนว่า DigiWin ไม่สามารถดำเนินการกับ Lead ที่พาร์ทเนอร์จองไว้ในช่วงที่มีผลบังคับ</div>\n              </div>\n              <div class="prot-proof">"Lead ของคุณถูกล็อค การคุ้มครองตามสัญญา ไม่ใช่แค่คำสัญญา"</div>\n            </div>\n            <div class="prot-card">\n              <div class="prot-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87m-4-12a4 4 0 010 7.75"/></svg></div>\n              <h3>สนับสนุน Co-Implementation</h3>\n              <div class="prot-points"><div class="prot-point"><strong>การสนับสนุนแบบแบ่งระดับ:</strong> คุณดูแล Tier 1 (คำถามผู้ใช้, Config พื้นฐาน) DigiWin ดูแล Tier 2 (Bug หลัก, API Failure, R&D)</div><div class="prot-point"><strong>Safety Net "บริการมอบอำนาจ":</strong> ถ้าคุณขายได้แต่ยังไม่มีกำลังส่งมอบ DigiWin ส่งมอบภายใต้แบรนด์ของคุณผ่านข้อตกลงอย่างเป็นทางการ</div><div class="prot-point"><strong>ช่วยเหลือ On-Site สำหรับ Pilot:</strong> สำหรับโปรเจกต์แรก เราให้คำแนะนำ On-Site สำหรับเฟสสำคัญ เช่น Go-Live Simulation</div>\n              </div>\n              <div class="prot-proof">"คุณไม่เคยอยู่คนเดียวตอน Go-Live"</div>\n            </div>\n            <div class="prot-card">\n              <div class="prot-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M22 10v6M2 10l10-5 10 5-10 5z"/><path d="M6 12v5c0 1.657 2.686 3 6 3s6-1.343 6-3v-5"/></svg></div>\n              <h3>การอบรมและรับรอง</h3>\n              <div class="prot-points"><div class="prot-point"><strong>การรับรองภาคบังคับ:</strong> พนักงานของคุณต้องจบหลักสูตรรับรองด้านการขาย Pre-sales และ Delivery ภายใน 3-5 เดือน</div><div class="prot-point"><strong>หลักสูตรตามบทบาท:</strong> T100 Certified → โปรเจกต์ Enterprise MES Certified → พื้นที่การผลิต Gold Status → มาร์จินสูงสุด</div><div class="prot-point"><strong>"Weaponization" ด้านการขาย:</strong> Whitepaper อุตสาหกรรม, เครื่องคำนวณ ROI, Demo Script ที่ Localize แล้ว — เข้าไปในฐานะที่ปรึกษาด้านการผลิต</div>\n              </div>\n              <div class="prot-proof">"ถ่ายทอดความสามารถ ไม่ใช่แค่คู่มือ"</div>\n            </div>\n            <div class="prot-card">\n              <div class="prot-icon"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" aria-hidden="true"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg></div>\n              <h3>สร้าง Demand</h3>\n              <div class="prot-points"><div class="prot-point"><strong>แจก Lead 100%:</strong> Lead จาก Brand Roadshow และ Digital Marketing ถูกแจกจ่าย 100% ให้พาร์ทเนอร์ที่ผ่านเกณฑ์และเข้าร่วม</div><div class="prot-point"><strong>Gold ได้สิทธิ์ก่อน:</strong> Lead คุณภาพสูงจาก Inbound ถูกจัดสรรตามผลงานให้ Gold Partner ก่อน</div><div class="prot-point"><strong>แบ่งงานกัน:</strong> เราสร้าง Demand คุณจับและให้บริการ เราเป็นเครื่องยนต์การตลาด คุณเป็นเครื่องยนต์ปิดดีล</div>\n              </div>\n              <div class="prot-proof">"เราเลี้ยงกองทัพ"</div>\n            </div>\n        </div>\n      </div>\n    </div>\n    <script>/**\n * DigiWin 数据洋流 (Data Ocean Current)\n *\n * Recreates the brand kit\'s signature visual: a 3D dot-grid surface\n * with dramatic rolling wave crests, viewed from a low angle.\n * Reference: DigiWin 2025 Annual Report cover, brand kit pp.61-68.\n *\n * Usage:\n *   <section data-particles>              — subtle on light bg (default)\n *   <section data-particles="bold">       — vivid on dark navy bg\n *   <section data-particles="medium">     — moderate visibility\n *\n * WordPress: wp_enqueue_script or Code Module. Self-initializing.\n */\n\n(function () {\n    \'use strict\';\n\n    var reducedMotion = window.matchMedia(\'(prefers-reduced-motion: reduce)\').matches;\n    var PI2 = Math.PI * 2;\n\n    // ── Brand colors (RGB) ──────────────────────────────────────────\n    var BLUE = [0, 175, 240];   // #00AFF0 Smart Blue\n    var CYAN = [0, 230, 255];   // #00E6FF Cyan accent\n\n    // ── Presets ─────────────────────────────────────────────────────\n    var PRESETS = {\n        light: {\n            frontOpacity: 0.18,   // visible but not distracting on white/light backgrounds\n            backOpacity: 0.03,\n            frontRadius: 3.5,\n            backRadius: 0.5,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.10\n        },\n        subtle: {\n            frontOpacity: 0.30,   // foreground dot opacity\n            backOpacity: 0.04,    // distant dot opacity\n            frontRadius: 4.5,     // foreground dot size (px)\n            backRadius: 0.6,      // distant dot size (px)\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.12\n        },\n        medium: {\n            frontOpacity: 0.45,\n            backOpacity: 0.06,\n            frontRadius: 5.0,\n            backRadius: 0.8,\n            color: BLUE,\n            colorAlt: CYAN,\n            altRatio: 0.18\n        },\n        bold: {\n            frontOpacity: 0.60,\n            backOpacity: 0.10,\n            frontRadius: 5.5,\n            backRadius: 1.0,\n            color: CYAN,\n            colorAlt: BLUE,\n            altRatio: 0.25\n        }\n    };\n\n    // ── Utility ─────────────────────────────────────────────────────\n    function lerp(a, b, t) { return a + (b - a) * t; }\n\n    // ── DataOcean class ─────────────────────────────────────────────\n    function DataOcean(el) {\n        this.el = el;\n        this.canvas = null;\n        this.ctx = null;\n        this.w = 0;\n        this.h = 0;\n        this.dpr = Math.min(window.devicePixelRatio || 1, 2);\n        this.visible = false;\n        this.raf = null;\n        this.time = 0;\n        this.resizeTimer = null;\n        this.colors = null; // pre-assigned per grid point\n\n        this.opts = this._parseOpts();\n        this._setup();\n        this._buildColors();\n        this._observe();\n\n        if (!reducedMotion) {\n            this._loop();\n        } else {\n            this.visible = true;\n            this._draw(0);\n        }\n    }\n\n    DataOcean.prototype._parseOpts = function () {\n        var name = this.el.getAttribute(\'data-particles\') || \'subtle\';\n        if (name === \'\' || name === \'true\') name = \'subtle\';\n        return PRESETS[name] || PRESETS.subtle;\n    };\n\n    DataOcean.prototype._setup = function () {\n        var c = document.createElement(\'canvas\');\n        c.setAttribute(\'aria-hidden\', \'true\');\n        c.style.cssText = \'position:absolute;inset:0;width:100%;height:100%;pointer-events:none;z-index:0;\';\n        var pos = getComputedStyle(this.el).position;\n        if (pos === \'static\') this.el.style.position = \'relative\';\n        this.el.style.overflow = \'hidden\';\n        this.el.insertBefore(c, this.el.firstChild);\n        this.canvas = c;\n        this.ctx = c.getContext(\'2d\');\n        this._resize();\n\n        var self = this;\n        window.addEventListener(\'resize\', function () {\n            clearTimeout(self.resizeTimer);\n            self.resizeTimer = setTimeout(function () {\n                self._resize();\n                self._buildColors();\n            }, 200);\n        });\n    };\n\n    DataOcean.prototype._resize = function () {\n        var r = this.el.getBoundingClientRect();\n        this.w = r.width;\n        this.h = r.height;\n        this.canvas.width = this.w * this.dpr;\n        this.canvas.height = this.h * this.dpr;\n        this.ctx.setTransform(this.dpr, 0, 0, this.dpr, 0, 0);\n    };\n\n    // Grid: ~55 cols × ~35 rows. Pre-assign a color to each dot.\n    DataOcean.prototype._buildColors = function () {\n        var cols = Math.min(65, Math.ceil(this.w / 22) + 4);\n        var rows = 35;\n        this._cols = cols;\n        this._rows = rows;\n        var n = cols * rows;\n        this.colors = new Array(n);\n        var alt = this.opts.altRatio;\n        for (var i = 0; i < n; i++) {\n            this.colors[i] = Math.random() < alt ? this.opts.colorAlt : this.opts.color;\n        }\n    };\n\n    DataOcean.prototype._observe = function () {\n        var self = this;\n        if (\'IntersectionObserver\' in window) {\n            this._obs = new IntersectionObserver(function (e) {\n                self.visible = e[0].isIntersecting;\n            }, { rootMargin: \'150px 0px\' });\n            this._obs.observe(this.el);\n        } else {\n            this.visible = true;\n        }\n    };\n\n    DataOcean.prototype._loop = function () {\n        var self = this;\n        var last = 0;\n        (function tick(ts) {\n            self.raf = requestAnimationFrame(tick);\n            if (!self.visible) return;\n            if (ts - last < 30) return; // ~30 fps\n            last = ts;\n            self.time += 0.006;\n            self._draw(self.time);\n        })(0);\n    };\n\n    /**\n     * ── Core renderer ───────────────────────────────────────────────\n     *\n     * Approach: Think of a flat grid of dots on a table, viewed from a\n     * low angle. The table surface undulates with large rolling waves.\n     *\n     * "depth" goes from 0 (nearest / bottom of screen) to 1 (farthest /\n     * top area). Everything scales with depth:\n     *   - dot size shrinks\n     *   - dot opacity fades\n     *   - vertical row spacing compresses (perspective foreshortening)\n     *   - horizontal dot spacing tightens\n     *   - wave amplitude diminishes\n     *\n     * The wave function creates 2-3 visible rolling crests that sweep\n     * diagonally across the surface — matching the annual report cover.\n     */\n    DataOcean.prototype._draw = function (t) {\n        var ctx = this.ctx;\n        var w = this.w;\n        var h = this.h;\n        var opts = this.opts;\n        var cols = this._cols;\n        var rows = this._rows;\n\n        ctx.clearRect(0, 0, w, h);\n\n        // ── Perspective layout ──────────────────────────────────────\n        //\n        // The wave occupies the bottom ~55% of the section.\n        // "horizon" is where distant rows converge (top of wave area).\n        // "ground" is the bottom edge of the section.\n\n        var ground = h + 10;               // bottom edge (+ small overflow)\n        var horizon = h * 0.35;            // where distant dots vanish toward\n        var totalSpan = ground - horizon;   // vertical pixel range for the wave\n\n        var idx = 0;\n\n        // Draw back-to-front for correct visual layering\n        for (var row = rows - 1; row >= 0; row--) {\n\n            // ── Depth (0 = near/bottom, 1 = far/top) ───────────────\n            var depth = row / (rows - 1);\n\n            // Non-linear depth mapping: compress more toward horizon\n            // This creates the "accelerating compression" of perspective\n            var mappedDepth = Math.pow(depth, 0.55);\n\n            // Screen Y baseline for this row (no wave yet)\n            var baseY = ground - mappedDepth * totalSpan;\n\n            // ── Per-row properties (lerp by depth) ──────────────────\n            var dotR = lerp(opts.frontRadius, opts.backRadius, depth);\n            var dotA = lerp(opts.frontOpacity, opts.backOpacity, depth);\n            var colSpacing = lerp(w / (cols - 4), w / (cols + 15), depth);\n\n            // Slight horizontal offset per row (creates diagonal sweep)\n            var rowShift = depth * w * 0.12;\n\n            // ── Wave: two layers for organic rolling feel ───────────\n            //\n            // Primary wave: large rolling crests (creates the signature look)\n            // Secondary wave: smaller ripple for naturalism\n            //\n            // Wave amplitude is BIG near foreground and diminishes with depth.\n            // This is what makes the crests dramatically visible.\n\n            var waveScale = (1 - depth * 0.75); // waves diminish into distance\n            var amp1 = 70 * waveScale;           // primary crest amplitude (px)\n            var amp2 = 25 * waveScale;           // secondary ripple\n\n            for (var col = 0; col < cols; col++) {\n                // Screen X\n                var screenX = col * colSpacing - rowShift + colSpacing * 0.5;\n\n                // Wrap X for seamless edge handling\n                if (screenX < -30 || screenX > w + 30) { idx++; continue; }\n\n                // ── Wave displacement ───────────────────────────────\n                //\n                // The primary wave sweeps diagonally (uses both col and row).\n                // freq values tuned so ~2 full crests are visible across width.\n\n                var worldX = col * 24; // stable world-space coordinate for wave\n                var worldZ = row * 18;\n\n                var wave = amp1 * Math.sin(\n                    worldX * 0.0065 + worldZ * 0.012 + t * 0.9\n                );\n                wave += amp2 * Math.sin(\n                    worldX * 0.013 - worldZ * 0.008 + t * 0.55 + 1.8\n                );\n\n                var screenY = baseY - wave;\n\n                // Skip if outside visible area\n                if (screenY < -15 || screenY > h + 15) { idx++; continue; }\n\n                // ── Draw dot ────────────────────────────────────────\n                var c = this.colors[idx % this.colors.length];\n                ctx.beginPath();\n                ctx.arc(screenX, screenY, dotR, 0, PI2);\n                ctx.fillStyle = \'rgba(\' + c[0] + \',\' + c[1] + \',\' + c[2] + \',\' + dotA + \')\';\n                ctx.fill();\n\n                idx++;\n            }\n        }\n    };\n\n    DataOcean.prototype.destroy = function () {\n        if (this.raf) cancelAnimationFrame(this.raf);\n        if (this._obs) this._obs.disconnect();\n        if (this.canvas && this.canvas.parentNode) {\n            this.canvas.parentNode.removeChild(this.canvas);\n        }\n    };\n\n    // ── Auto-init ───────────────────────────────────────────────────\n    function init() {\n        var els = document.querySelectorAll(\'[data-particles]\');\n        var inst = [];\n        for (var i = 0; i < els.length; i++) inst.push(new DataOcean(els[i]));\n\n        window.DigiWinParticleOcean = {\n            instances: inst,\n            DataOcean: DataOcean,\n            refresh: function () {\n                for (var j = 0; j < inst.length; j++) inst[j].destroy();\n                inst = [];\n                var els2 = document.querySelectorAll(\'[data-particles]\');\n                for (var k = 0; k < els2.length; k++) inst.push(new DataOcean(els2[k]));\n                this.instances = inst;\n            }\n        };\n    }\n\n    if (document.readyState === \'loading\') {\n        document.addEventListener(\'DOMContentLoaded\', init);\n    } else {\n        init();\n    }\n})();\n</script><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: คุยตัวเลขสำหรับบริษัทของคุณ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: คุยตัวเลขสำหรับบริษัทของคุณ: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: คุยตัวเลขสำหรับบริษัทของคุณ: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ec-cta-section">\n    <div class="ec-cta-super-d" aria-hidden="true"></div>\n    \n    <div class="ec-cta-container">\n      <h2 class="ec-cta-title">พร้อมคำนวณตัวเลขสำหรับบริษัทคุณหรือยัง?</h2>\n      <p class="ec-cta-subtitle">มาคุยเรื่องพื้นที่ เป้าหมาย และสร้างประมาณการ 3 ปีเฉพาะสำหรับธุรกิจของคุณ ไม่มีข้อผูกมัด — แค่ความจริงจากสเปรดชีท</p>\n      <div class="ec-cta-btn-row">\n        <a href="/th/demo/" class="ec-cta-btn ec-cta-btn--primary">พูดคุยกับเรา</a>\n        <a href="/partner-program/" class="ec-cta-btn ec-cta-btn--ghost">กลับไปภาพรวมพาร์ทเนอร์</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100775;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100775 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100775, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === PARTNER ECONOMICS HERO === */\n.econ-hero-section{background:linear-gradient(135deg,#000432 0%,#000864 50%,#001080 100%);padding:140px 24px 100px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.econ-hero-section::before{content:\'\';position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,0.03) 1.5px,transparent 1.5px);background-size:60px 60px;pointer-events:none;z-index:0}\n.econ-hero-grain::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.econ-hero-grain{position:absolute;inset:0;z-index:1;opacity:0.16}\n.econ-hero-d-bg{position:absolute;top:auto;right:-10%;bottom:-20%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center bottom;background-size:contain;opacity:0.16;pointer-events:none;z-index:0}\n.econ-hero-dot-overlay{position:absolute;inset:0;background-image:radial-gradient(circle,rgba(255,255,255,0.03) 1.5px,transparent 1.5px);background-size:60px 60px;pointer-events:none;z-index:1}\n.econ-hero-inner{max-width:900px;margin:0 auto;position:relative;z-index:3}\n.econ-hero-breadcrumb{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-bottom:24px}\n.econ-hero-breadcrumb a{color:rgba(255,255,255,0.85);text-decoration:none;transition:color 0.2s}\n.econ-hero-breadcrumb a:hover{color:#00AFF0}\n.econ-hero-breadcrumb span{margin:0 8px}\n.econ-hero-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(36px,5vw,52px);font-weight:700;color:#fff;line-height:1.15;margin:0 0 24px;padding:0}\n.econ-hero-hl{color:#4ade80}\n.econ-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0 0 48px;padding:0}\n.econ-hero-proof{display:grid;grid-template-columns:repeat(4,1fr);gap:24px;padding-top:40px;border-top:1px solid rgba(255,255,255,0.1)}\n.econ-hero-proof-item{text-align:center}\n.econ-hero-proof-value{font-family:\'Noto Sans\',sans-serif;font-size:32px;font-weight:700;color:#15803d;display:block;margin-bottom:8px}\n.econ-hero-proof-label{font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;color:rgba(255,255,255,0.8);text-transform:uppercase;letter-spacing:0.5px}\n@media(max-width:1024px){\n  .econ-hero-section{padding:120px 24px 80px}\n  .econ-hero-proof{grid-template-columns:repeat(2,1fr)}\n}\n@media(max-width:768px){\n  .econ-hero-section{padding:100px 20px 60px}\n  .econ-hero-proof{grid-template-columns:1fr 1fr;gap:16px}\n  .econ-hero-proof-value{font-size:24px}\n}\n@media(prefers-reduced-motion:reduce){.econ-hero-breadcrumb a{transition:none !important}}\n.et_pb_section .econ-hero-proof-label {\n            line-height: 19.2px !important;\n        }\n\n.et_pb_section .econ-hero-proof-value {\n            line-height: 51.2px !important;\n        }\n/* === REVENUE MODEL SECTION (S2) === */\n.rev-section{padding:100px 24px;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.rev-scene-wrap{position:absolute;inset:0;pointer-events:none;z-index:0}\n.rev-scene-wrap svg{width:100%;height:100%;position:absolute;top:0;left:0;opacity:0.20}\n.rev-wave-top{position:absolute;top:0;left:0;right:0;height:120px;opacity:0.10;background:linear-gradient(180deg,rgba(0,175,240,0.15) 0%,transparent 100%);pointer-events:none;z-index:1}\n.rev-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.rev-header{text-align:center;margin-bottom:60px}\n.rev-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.2em;color:#0369a1;display:block;margin-bottom:16px}\n.rev-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.rev-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.rev-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.rev-stream{background:#fff;border:1px solid #e2e8f0;border-radius:20px;overflow:hidden;transition:all 0.3s ease}\n.rev-stream:hover{box-shadow:0 12px 40px rgba(0,0,0,0.08);border-color:#cbd5e1}\n.rev-stream-header{background:linear-gradient(135deg,#000864 0%,#000432 100%);padding:24px;display:flex;align-items:center;gap:16px;flex-wrap:wrap}\n.rev-stream-icon{width:48px;height:48px;background:rgba(255,255,255,0.1);border-radius:12px;display:flex;align-items:center;justify-content:center}\n.rev-stream-icon svg{width:24px;height:24px;stroke:#4ade80}\n.rev-stream-header h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;line-height:1.6;flex:1;margin:0;padding:0}\n.rev-stream-tag{font-family:\'JetBrains Mono\',monospace;font-size:10px;font-weight:500;color:#15803d;background:rgba(74,222,128,0.15);padding:4px 10px;border-radius:50px}\n.rev-stream-body{padding:24px}\n.rev-stream-desc{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#5b6b80;line-height:1.6;margin:0 0 20px;padding:0}\n.rev-margin-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px}\n.rev-margin-item{background:#f8fafc;border-radius:12px;padding:16px}\n.rev-margin-level{font-family:\'Noto Sans\',sans-serif;font-size:12px;color:#5b6b80;display:block;margin-bottom:6px}\n.rev-margin-value{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864}\n.rev-margin-value.highlight{color:#15803d}\n.rev-stream-note{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666666;font-style:italic;margin:0;padding:0}\n@media(max-width:1024px){\n  .rev-grid{grid-template-columns:1fr}\n  .rev-margin-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .rev-section{padding:80px 20px}\n  .rev-margin-grid{grid-template-columns:1fr}\n}\n@media(prefers-reduced-motion:reduce){.rev-stream{transition:none !important}}\n/* Divi line-height overrides */\n.et_pb_section .rev-label{line-height:19.2px !important;margin-bottom:12px}\n.et_pb_section .rev-title{line-height:64px !important}\n.et_pb_section .rev-stream-tag{line-height:16px !important}\n.et_pb_section .rev-margin-level{line-height:19.2px !important}\n.et_pb_section .rev-margin-value{line-height:28.8px !important}\n.et_pb_section .rev-stream-note{line-height:22.4px !important}\n/* === 3-YEAR JOURNEY SECTION (S3) === */\n.jny-section{padding:100px 24px;background:linear-gradient(180deg,#f8fafc 0%,#fff 100%);position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.jny-scene-wrap{position:absolute;inset:0;pointer-events:none;z-index:0}\n.jny-scene-wrap svg{width:100%;height:100%;position:absolute;top:0;left:0;opacity:0.20}\n.jny-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.jny-header{text-align:center;margin-bottom:60px}\n.jny-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.2em;color:#0369a1;display:block;margin-bottom:16px}\n.jny-title{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.jny-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n\n/* Year Cards Grid */\n.jny-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px;margin-bottom:48px}\n.jny-phase{background:#fff;border:1px solid #e2e8f0;border-radius:20px;overflow:hidden;transition:all 0.3s ease;display:flex;flex-direction:column}\n.jny-phase:hover{box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.jny-phase.featured{border-color:#4ade80;box-shadow:0 0 0 3px rgba(74,222,128,0.2)}\n\n/* Phase Headers */\n.jny-phase-header{padding:24px;position:relative}\n.jny-phase-header.year-1{background:linear-gradient(135deg,#94a3b8,#5b6b80)}\n.jny-phase-header.year-2{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.jny-phase-header.year-3{background:linear-gradient(135deg,#4ade80,#22c55e)}\n.jny-badge{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;color:rgba(255,255,255,0.8);background:rgba(255,255,255,0.2);padding:4px 12px;border-radius:50px;margin-bottom:12px;display:inline-block}\n.jny-phase-header h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:700;color:#fff;line-height:1.6;margin:0 0 8px;padding:0}\n.jny-status{font-family:\'Noto Sans\',sans-serif;font-size:13px;color:rgba(255,255,255,0.8)}\n\n/* Phase Body */\n.jny-phase-body{padding:24px;flex:1;display:flex;flex-direction:column}\n.jny-reality{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;line-height:1.6;margin:0 0 20px;padding:16px;background:#f8fafc;border-radius:12px}\n.jny-activity{margin-bottom:20px;padding:12px 16px;background:#eff6ff;border-radius:12px;min-height:72px}\n.jny-activity-label{font-family:\'Noto Sans\',sans-serif;font-size:12px;color:#5b6b80;display:block;margin-bottom:4px}\n.jny-activity-value{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864}\n\n/* Math Block */\n.jny-math{background:#f8fafc;border-radius:12px;padding:16px;margin-bottom:16px;margin-top:auto}\n.jny-math-row{display:flex;justify-content:space-between;align-items:baseline;padding:8px 0;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;border-bottom:1px solid #e2e8f0;gap:12px}\n.jny-math-row:last-child{border-bottom:none}\n.jny-math-row>span:first-child{flex-shrink:0;white-space:nowrap}\n.jny-math-value{font-weight:600;color:#000864;text-align:right}\n.jny-math-value.dim{color:#5b6b80}\n.jny-math-value.highlight{color:#15803d}\n.jny-math-total{display:flex;justify-content:space-between;align-items:baseline;padding-top:12px;margin-top:8px;border-top:2px solid #e2e8f0;gap:12px}\n.jny-math-total>span:first-child{font-family:\'Noto Sans\',sans-serif;font-weight:600;color:#000864;flex-shrink:0;white-space:nowrap}\n.jny-math-total-value{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:700;color:#15803d;text-align:right}\n.jny-outcome{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n.jny-outcome .highlight{color:#15803d}\n\n/* Summary Box with Bar Chart */\n.jny-summary{background:linear-gradient(135deg,#000864 0%,#000432 100%);border-radius:20px;padding:48px 48px 80px;text-align:center}\n.jny-summary-title{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:600;color:#fff;line-height:1.6;margin:0 0 32px;padding:0}\n.jny-bars{display:flex;align-items:flex-end;justify-content:center;gap:32px;height:200px}\n.jny-bar{width:100px;border-radius:8px 8px 0 0;display:flex;flex-direction:column;justify-content:flex-start;align-items:center;padding-top:16px;position:relative;background:linear-gradient(180deg,#00AFF0,#003CC8)}\n.jny-bar.featured{background:linear-gradient(180deg,#4ade80,#22c55e)}\n.jny-bar--y1{height:27%}\n.jny-bar--y2{height:63%}\n.jny-bar--y3{height:100%}\n.jny-bar-value{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:700;color:#fff}\n.jny-bar-label{position:absolute;bottom:-32px;font-family:\'Noto Sans\',sans-serif;font-size:13px;color:rgba(255,255,255,0.85);white-space:nowrap}\n\n/* Responsive */\n@media(max-width:1024px){\n  .jny-grid{grid-template-columns:1fr}\n  .jny-bars{gap:16px}\n  .jny-bar{width:80px}\n}\n@media(max-width:768px){\n  .jny-section{padding:80px 20px}\n  .jny-summary{padding:32px 24px 64px}\n  .jny-bars{height:150px}\n}\n@media(prefers-reduced-motion:reduce){.jny-phase{transition:none !important}}\n/* Divi line-height + styling overrides */\n.et_pb_section .jny-label{line-height:19.2px !important;font-size:12px;color:#0369a1}\n.et_pb_section .jny-title{font-size:40px !important;font-weight:700 !important;line-height:64px !important;color:#000864 !important;margin-bottom:16px !important}\n.et_pb_section .jny-badge{line-height:17.6px !important}\n.et_pb_section .jny-status{line-height:20.8px !important}\n.et_pb_section .jny-activity-label{font-weight:400 !important;line-height:19.2px !important}\n.et_pb_section .jny-activity-value{line-height:22.4px !important}\n.et_pb_section .jny-math-value{line-height:22.4px !important}\n.et_pb_section .jny-math-total-value{line-height:28.8px !important}\n.et_pb_section .jny-bar-value{line-height:28.8px !important}\n.et_pb_section .jny-bar-label{line-height:20.8px !important}\n/* === PROTECTION SECTION (S4) === */\n.prot-section{padding:100px 24px;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.prot-wave-right{position:absolute;top:0;right:0;bottom:0;width:200px;opacity:0.05;background:linear-gradient(90deg,transparent 0%,rgba(0,175,240,0.15) 100%);pointer-events:none;z-index:0}\n.prot-inner{max-width:1200px;margin:0 auto;position:relative;z-index:2}\n.prot-header{text-align:center;margin-bottom:60px}\n.prot-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.2em;color:#0369a1;display:block;margin-bottom:16px}\n.prot-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(32px,3.5vw,44px);font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.prot-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n.prot-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.prot-card{background:linear-gradient(180deg,#f8fafc 0%,#fff 100%);border:1px solid #e2e8f0;border-radius:20px;padding:32px;transition:all 0.3s ease}\n.prot-card:hover{box-shadow:0 12px 40px rgba(0,0,0,0.08);border-color:#00AFF0}\n.prot-icon{width:56px;height:56px;background:linear-gradient(135deg,#00AFF0,#003CC8);border-radius:16px;display:flex;align-items:center;justify-content:center;margin-bottom:20px}\n.prot-icon svg{width:28px;height:28px;stroke:#fff}\n.prot-card h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 20px;padding:0}\n.prot-points{margin-bottom:20px}\n.prot-point{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80;line-height:1.6;padding:12px 0;border-bottom:1px solid #f1f5f9}\n.prot-point:last-child{border-bottom:none}\n.prot-point strong{color:#000864;display:block;margin-bottom:4px}\n.prot-proof{font-family:\'Noto Sans\',sans-serif;font-size:13px;font-style:italic;color:#15803d;background:#f0fdf4;padding:12px 16px;border-radius:12px;text-align:center}\n@media(max-width:1024px){\n  .prot-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .prot-section{padding:80px 20px}\n}\n@media(prefers-reduced-motion:reduce){.prot-card{transition:none !important}}\n.et_pb_section .prot-label {\n            line-height: 19.2px !important;\n        \n            margin-bottom: 12px;\n}\n\n.et_pb_section .prot-proof {\n            line-height: 20.8px !important;\n        }\n/* === CTA: คุยตัวเลขสำหรับบริษัทของคุณ === */\n.ec-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ec-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.ec-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.ec-cta-super-d{position:absolute;top:50%;right:-10%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;transform:translateY(-50%);opacity:0.18;pointer-events:none;z-index:0;animation:superDGlow 3s ease-in-out infinite}\n@keyframes superDGlow{0%,100%{filter:drop-shadow(0 0 20px rgba(0,175,240,0.1))}50%{filter:drop-shadow(0 0 40px rgba(0,175,240,0.25))}}\n\n.ec-cta-container{position:relative;z-index:3;max-width:800px;margin:0 auto;text-align:center}\n.ec-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.ec-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.9);margin:0 0 40px;max-width:600px;margin-left:auto;margin-right:auto}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .ec-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .ec-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .ec-cta-container p{padding-bottom:0 !important}\n\n.ec-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.ec-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.ec-cta-btn:hover::before{left:100%}\n.ec-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.ec-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.ec-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.ec-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.ec-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.ec-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .ec-cta-title{font-size:28px;margin-bottom:16px}\n  .ec-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .ec-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .ec-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.ec-cta-btn{transition:none !important}.ec-cta-btn::before{display:none}}\n.et_pb_section .ec-cta-btn--ghost{color:#fff !important}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

